// src/modules/members/service.js
const projectsService = require('../projects/service');
const { randomUUID } = require('node:crypto');

const addMember = async (projectId, member) => {
  const project = await projectsService.getProject(projectId);
  if (!project) {
    return null;
  }

  const existingMember = project.members.find(m => m.userId === member.userId);
  if (existingMember) {
    return null;
  }

  const newMember = { id: randomUUID(), ...member };
  project.members.push(newMember);
  await projectsService.saveProject(project);
  return newMember;
};

module.exports = { addMember };
module.exports.createMember = module.exports.addMember;

// src/modules/comments/service.js
const tasksService = require('../tasks/service');
const { randomUUID } = require('node:crypto');

const addComment = async (projectId, taskId, comment) => {
  const task = await tasksService.getTasks(projectId).find(t => t.id === taskId);
  if (!task) {
    return null;
  }

  const newComment = { id: randomUUID(), ...comment };
  task.comments.push(newComment);
  await tasksService.saveTask(task);
  return newComment;
};

module.exports = { addComment };
module.exports.createComment = module.exports.addComment;

